{
  "description": "The quiz evaluates a developer's knowledge of advanced HTML5 semantic elements beyond basic tags like <div> and <span>, measuring both conceptual understanding and practical usage. It is positioned as a moderate‑difficulty, light‑hearted challenge with a friendly, encouraging tone that nudges learners to improve their markup skills. The format mixes code snippets with informal commentary to keep the experience engaging.",
  "topics": [
    "HTML5 semantic elements",
    "Proper use of <header>, <nav>, <section>, <article>, <footer>, etc.",
    "Accessibility and SEO implications of semantic markup",
    "Differences between generic and semantic tags"
  ],
  "audience": "Front‑end web developers and web design students who are comfortable with basic HTML and want to validate or deepen their semantic HTML knowledge."
}
